# Follows the Latin-Script Uyghur alphabet 2001-todate rules defined at ←http://ukij.org/html/ , https://en.wikipedia.org/wiki/Uyghur_Latin_alphabet, http://www.uyghurdictionary.org/excerpts/An%20Introduction%20to%20LSU.pdf
#  Rules are predicated on running NFD first, and NFC afterward
:: NFD (NFC) ;
$lsuVowels = [aAeEoOuUöÖüÜéÉiI’'] ;
$disambig =  ̱ ;
[:Separator:]* → ' ';
$space = [:Separator:]*;
٫ ↔ ',' $disambig ; # ARABIC DECIMAL SEPARATOR
، ↔ ',' ; # ARABIC COMMA
؛ ↔ ';' ; # ARABIC SEMICOLON
؟ ↔ '?' ; # ARABIC QUESTION MARK
› ↔ ‘ ;
‹ ↔ ’ ;
ئ → ;
# Uyghur Hamza
ـ → ;
# ARABIC/UYGHUR TATWEEL
# special treatment for Uyghur hamza
ئا ← $space { [aA] ;
ئە ← $space { [eE] ;
ئو ← $space { [oO] ;
ئۇ ← $space { [uU] ;
ئۆ ← $space { [öÖ] ;
ئۈ ← $space { [üÜ] ;
ئې ← $space { [éÉ] ;
ئى ← $space { [iI] ;
ئا ← $lsuVowels { [aA] ;
ئە ← $lsuVowels { [eE] ;
ئو ← $lsuVowels { [oO] ;
ئۇ ← $lsuVowels { [uU] ;
ئۆ ← $lsuVowels { [öÖ] ;
ئۈ ← $lsuVowels { [üÜ] ;
ئې ← $lsuVowels { [éÉ] ;
ئى ← $lsuVowels { [iI] ;
# special treatment for apostrof
سھ ← s [’'] { h ;
نغ ← n [’'] { gh ;
نگ ← n [’'] { g ;
ڭھ ← ng [’'] { h ;
سھ ← S [’'] { H ;
نغ ← N [’'] { GH ;
نگ ← N [’'] { G ;
ڭھ ← NG [’'] { H ;
# special treatment for apostrof
سھ → s''h ;
نغ → n''gh ;
نگ → n''g ;
ڭھ → ng''h ;
# following 4 were duplicates.
#سھ → S''H ;
# نغ → N''GH ;
# نگ → N''G ;
# ڭھ → NG''H ;

# disambiguation for ژ by covering the most common words with ژ
